script:
frappe.ui.form.on('Student Applicant', {
    refresh: function(frm) {
        frm.set_intro('');

        if (frm.doc.student_email_id) {
            frm.set_intro(
                '<b>Student Email:</b> ' + frm.doc.student_email_id,
                'blue'
            );
            frm.set_df_property('student_email_id', 'read_only', 1);
            frm.refresh_field('student_email_id');
        } else if (!frm.is_new()) {
            frm.set_intro('Generating student email...', 'yellow');
            frappe.call({
                method: 'edvronix.edvronix_app.api.student_applicant.generate_email_now',
                args: { applicant_name: frm.doc.name },
                callback: function(r) {
                    if (r.message) {
                        frm.doc.student_email_id = r.message;
                        frm.set_intro(
                            '<b>Student Email:</b> ' + r.message,
                            'blue'
                        );
                        frm.set_df_property('student_email_id', 'read_only', 1);
                        frm.refresh_field('student_email_id');
                    } else {
                        frm.set_intro('Could not auto-generate email. Please fill it manually.', 'red');
                    }
                }
            });
        }
    }
});

frappe.listview_settings['Student'] = frappe.listview_settings['Student'] || {};

frappe.listview_settings['Student'].add_fields = ['reason_for_leaving'];

frappe.listview_settings['Student'].get_indicator = function(doc) {
    if (doc.enabled) {
        return [__('Active'), 'green', 'enabled,=,1'];
    } else if (doc.reason_for_leaving === 'Graduated') {
        return [__('Graduated'), 'purple', 'enabled,=,0|reason_for_leaving,=,Graduated'];
    } else {
        return [__('Disabled'), 'red', 'enabled,=,0'];
    }
};

frappe.ui.form.on('Student', {
    refresh: function(frm) {
        if (!frm.doc.enabled && frm.doc.reason_for_leaving === 'Graduated') {
            frm.set_df_property('enabled', 'read_only', 1);
            frm.refresh_field('enabled');

            frappe.db.get_list('Graduation Student Detail', {
                filters: { student: frm.doc.name },
                fields: ['parent'],
                limit: 1
            }).then(function(rows) {
                let doc_link = '';
                if (rows && rows.length) {
                    let grad_name = rows[0].parent;
                    doc_link = ' <a href="/app/student-graduation/' + encodeURIComponent(grad_name) + '"><b>' + grad_name + '</b></a>';
                }
                frm.set_intro(
                    'This student has <b>Graduated</b>' +
                    (frm.doc.date_of_leaving ? ' on ' + frappe.datetime.str_to_user(frm.doc.date_of_leaving) : '') + '.' +
                    (frm.doc.leaving_certificate_number ? ' Certificate No: <b>' + frm.doc.leaving_certificate_number + '</b>' : '') +
                    '<br><small>To restore this student, cancel the graduation document:' + doc_link + '</small>',
                    'green'
                );
            });
        }

        if (!frm.is_new() && frm.doc.enabled) {
            frm.add_custom_button(__('Graduate Student'), function() {
                frappe.prompt([
                    {
                        fieldname: 'graduation_date',
                        fieldtype: 'Date',
                        label: __('Graduation Date'),
                        reqd: 1,
                        default: frappe.datetime.get_today()
                    },
                    {
                        fieldname: 'certificate_number',
                        fieldtype: 'Data',
                        label: __('Certificate Number (optional)')
                    },
                    {
                        fieldname: 'notes',
                        fieldtype: 'Small Text',
                        label: __('Notes (optional)')
                    }
                ],
                function(values) {
                    frappe.call({
                        method: 'edvronix.edvronix_app.doctype.student_graduation.student_graduation.graduate_single_student',
                        args: {
                            student: frm.doc.name,
                            graduation_date: values.graduation_date,
                            certificate_number: values.certificate_number || '',
                            notes: values.notes || ''
                        },
                        freeze: true,
                        freeze_message: __('Graduating student...'),
                        callback: function(r) {
                            if (r.message && r.message.success) {
                                frappe.show_alert({ message: __('Student graduated successfully.'), indicator: 'green' });
                                frm.reload_doc();
                            }
                        }
                    });
                },
                __('Graduate Student'),
                __('Confirm')
                );
            }, __('Actions'));
        }
    }
});
